def binomial(n: int, k: int) -> int:
    if k == 0 or k == n: return 1
    if 0 <= k <= n: return F(n) // (F(k) * F(n - k))
    if k <= n <  0: return F(-k - 1) // (F(n - k) * F(-1 - n)) * (-1) ** (n - k)
